  // game-src/collisions.ts
  var SHAKE_INTENSITY_PX = 14;
  var SHAKE_DURATION_SEC = 0.35;
  var ENEMY_HIT_ARM_FRAC = 0.7;
  function flightT(b) {
    const v = b.getVariables();
    const flightTime = v.get("flightTime").getAsNumber() || 2.25;
    return v.get("elapsed").getAsNumber() / flightTime;
  }
  function bulletOverHull(b, e) {
    const bx = b.getX() + b.getWidth() / 2;
    const by = b.getY() + b.getHeight() / 2;
    const ex = e.getX();
    const ey = e.getY();
    const ew = e.getWidth();
    const eh = e.getHeight();
    return bx >= ex + ew * 0.2 && bx <= ex + ew * 0.8 && by >= ey + eh * 0.42 && by <= ey + eh * 0.95;
  }
  var BULLET_DAMAGE = 1;
  var BULLET_BODY_DAMAGE = 0.25;
  var CHARGED_MULTIPLIER = 2.5;
  var CHARGED_INTERCEPTED_MULTIPLIER = 1.25;
  var ENEMY_BALL_DAMAGE = 1;
  function bulletDamage(charged, intercepted, body) {
    const base = body ? BULLET_BODY_DAMAGE : BULLET_DAMAGE;
    if (!charged) return base;
    return base * (intercepted ? CHARGED_INTERCEPTED_MULTIPLIER : CHARGED_MULTIPLIER);
  }
  function hit(a, b) {
    return gdjs.RuntimeObject.collisionTest(a, b, false);
  }
  function resolveBulletHits(scene2) {
    const bullets = all(scene2, ObjectName.Bullet).concat(all(scene2, ObjectName.ChargedBullet));
    if (bullets.length === 0) return { kills: 0, parries: 0 };
    const targets = all(scene2, ObjectName.Target);
    const enemyBalls = all(scene2, ObjectName.EnemyBall);
    let kills = 0;
    let parries = 0;
    for (const b of bullets) {
      let consumed = false;
      const charged = b.getVariables().get("charged").getAsNumber() === 1;
      for (const eb of enemyBalls) {
        if (hit(b, eb)) {
          eb.deleteFromScene(scene2);
          if (charged) {
            b.getVariables().get("intercepted").setNumber(1);
            parries += 1;
          } else {
            b.deleteFromScene(scene2);
            parries += 1;
            consumed = true;
          }
          break;
        }
      }
      if (consumed) continue;
      if (b.getVariables().get("landed").getAsNumber() !== 1) continue;
      const intercepted = b.getVariables().get("intercepted").getAsNumber() === 1;
      let handled = false;
      for (const t of targets) {
        if (hit(b, t)) {
          const dmg = bulletDamage(
            charged,
            intercepted,
            /*body*/
            false
          );
          b.deleteFromScene(scene2);
          const ship = findShipForTarget(scene2, t);
          const state = ship ? ship.getVariables().get("state").getAsNumber() : 0;
          if (ship && state === 1) {
            flash(
              ship,
              /*direct*/
              true
            );
            if (damage(scene2, ship, dmg)) kills += 1;
          }
          handled = true;
          break;
        }
      }
      if (handled) continue;
      for (const e of all(scene2, ObjectName.Enemy)) {
        if (bulletOverHull(b, e)) {
          const state = e.getVariables().get("state").getAsNumber();
          if (state === 1) {
            const dmg = bulletDamage(
              charged,
              intercepted,
              /*body*/
              true
            );
            flash(
              e,
              /*direct*/
              false
            );
            if (damage(scene2, e, dmg)) kills += 1;
          }
          b.deleteFromScene(scene2);
          break;
        }
      }
    }
    return { kills, parries };
  }
  function resolveEnemyBallHits(scene2, cannon2) {
    if (!cannon2) return 0;
    const balls = all(scene2, ObjectName.EnemyBall);
    if (balls.length === 0) return 0;
    let dmg = 0;
    for (const b of balls) {
      if (flightT(b) < ENEMY_HIT_ARM_FRAC) continue;
      if (hit(b, cannon2)) {
        b.deleteFromScene(scene2);
        damagePlayer(scene2, ENEMY_BALL_DAMAGE);
        trigger(scene2, SHAKE_INTENSITY_PX, SHAKE_DURATION_SEC);
        dmg += ENEMY_BALL_DAMAGE;
      }
    }
    return dmg;
  }

  // game-src/hud-health.ts
