  // game-src/audio.ts
  var KEY2 = "__dtdAudioCtx";
  function ctx() {
    const g = globalThis;
    if (g[KEY2]) return g[KEY2];
    const AC = g.AudioContext || g.webkitAudioContext;
    if (!AC) return null;
    try {
      g[KEY2] = new AC();
    } catch {
      return null;
    }
    return g[KEY2];
  }
  function resume(c) {
    if (c && c.state === "suspended" && typeof c.resume === "function") c.resume();
  }
  function tone(c, type, freqStart, freqEnd, t0, dur, peak) {
    const o = c.createOscillator();
    const g = c.createGain();
    o.type = type;
    o.frequency.setValueAtTime(freqStart, t0);
    if (freqEnd !== freqStart) o.frequency.exponentialRampToValueAtTime(Math.max(1, freqEnd), t0 + dur);
    g.gain.setValueAtTime(1e-4, t0);
    g.gain.exponentialRampToValueAtTime(peak, t0 + 0.015);
    g.gain.exponentialRampToValueAtTime(1e-4, t0 + dur);
    o.connect(g).connect(c.destination);
    o.start(t0);
    o.stop(t0 + dur + 0.02);
  }
  function playCatch() {
    const c = ctx();
    if (!c) return;
    resume(c);
    const now = c.currentTime;
    tone(c, "triangle", 660, 680, now, 0.18, 0.28);
    tone(c, "triangle", 990, 1010, now + 0.07, 0.22, 0.28);
    tone(c, "sine", 1480, 1500, now + 0.14, 0.2, 0.18);
    tone(c, "sine", 200, 90, now, 0.16, 0.3);
  }
  function playExplosion() {
    const c = ctx();
    if (!c) return;
    resume(c);
    const now = c.currentTime;
    const dur = 0.55;
    const buffer = c.createBuffer(1, Math.floor(c.sampleRate * dur), c.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < data.length; i++) {
      const decay = Math.pow(1 - i / data.length, 2);
      data[i] = (Math.random() * 2 - 1) * decay;
    }
    const src = c.createBufferSource();
    src.buffer = buffer;
    const lp = c.createBiquadFilter();
    lp.type = "lowpass";
    lp.frequency.setValueAtTime(1200, now);
    lp.frequency.exponentialRampToValueAtTime(120, now + dur);
    const g = c.createGain();
    g.gain.setValueAtTime(0.55, now);
    g.gain.exponentialRampToValueAtTime(1e-3, now + dur);
    src.connect(lp).connect(g).connect(c.destination);
    src.start(now);
    src.stop(now + dur);
    tone(c, "sine", 130, 42, now, 0.4, 0.45);
  }
