        break;
      case P2.DEMO_EXPLODE:
        if (!lessonCannon) {
          consumeCatchArm(scene2);
          const side = Math.random() < 0.5 ? -1 : 1;
          vars.get(V_P2_CATCH_AIM).setNumber(AIM_CENTER_DEG + side * CATCH_SIDE_OFFSET_DEG);
          const id = spawnLessonCannon(scene2, w(scene2) * (0.5 + side * 0.18));
          vars.get(V_P2_CANNON).setNumber(id);
          showP2Hint(scene2, side > 0 ? "Now YOU try!\nAim RIGHT to catch the shot." : "Now YOU try!\nAim LEFT to catch the shot.");
          setP2(scene2, P2.LEARN_SCROLL);
        } else if (returnGone && !isCatchArmed(scene2)) {
          armCatchCan(scene2);
          setP2(scene2, P2.DEMO_CAUGHT);
        }
        break;
      case P2.LEARN_SCROLL:
        if (settleLessonCannon(lessonCannon)) setP2(scene2, P2.LEARN_SETTLE);
        break;
      case P2.LEARN_SETTLE:
        if (t >= P2_SETTLE_SEC + 0.6) setP2(scene2, P2.LEARN_FLASH);
        break;
      case P2.LEARN_FLASH:
        if (lessonCannon) flashCannon(lessonCannon, t);
        if (t >= P2_FLASH_SEC) {
          if (lessonCannon) {
            lessonCannon.setColor("255;255;255");
            fireLessonBall(scene2, lessonCannon, cannon2, vars.get(V_P2_CATCH_AIM).getAsNumber());
          }
          showP2Hint(scene2, "Point the bore at the incoming ball to catch it!");
          setP2(scene2, P2.LEARN_FLIGHT);
        }
        break;
      case P2.LEARN_FLIGHT:
        if (isCatchArmed(scene2)) {
          showP2Hint(scene2, "Caught! Now fire it back!");
          setP2(scene2, P2.LEARN_CAUGHT);
        } else if (ballsGone) {
          showP2Hint(scene2, "Missed! Aim the bore at the ball \u2014 try again.");
          setP2(scene2, P2.LEARN_FLASH);
        }
        break;
      case P2.LEARN_CAUGHT:
        if (!isCatchArmed(scene2) || !lessonCannon) setP2(scene2, P2.LEARN_EXPLODE);
        break;
      case P2.LEARN_EXPLODE:
        if (!lessonCannon) {
          consumeCatchArm(scene2);
          showP2Hint(scene2, "Catch-Can mastered!", 2.5);
          setP2(scene2, P2.DONE);
        } else if (returnGone && !isCatchArmed(scene2)) {
          armCatchCan(scene2);
          showP2Hint(scene2, "So close \u2014 aim at the cannon and fire!");
          setP2(scene2, P2.LEARN_CAUGHT);
        }
        break;
      default:
        break;
    }
  }
  var L2_RELOAD_SEC = 0.2;
  var L2_CHARGE_DELAY_SEC = 0.3;
  var L2_NORMAL_FLIGHT_SEC = 0.8;
  var L2_CHARGED_FLIGHT_SEC = L2_NORMAL_FLIGHT_SEC / 1.25;
  var V_FIRE_CD = "__l2FireCd";
  var V_CHARGE_T = "__l2ChargeT";
  var V_QUEUED = "__l2Queued";
  var CHARGED_OPTS = { flightTimeSec: L2_CHARGED_FLIGHT_SEC, wobble: false };
  function handleFire(scene2, dt2, cannon2, aimDeg, tap, doubleTap) {
    const vars = scene2.getVariables();
    const cd = Math.max(0, vars.get(V_FIRE_CD).getAsNumber() - dt2);
    vars.get(V_FIRE_CD).setNumber(cd);
    if ((tap || doubleTap) && isCatchArmed(scene2)) {
      fireBallAt(
        scene2,
        cannon2,
        aimDeg,
        /*charged*/
        true,
        CHARGED_OPTS
      );
      consumeCatchArm(scene2);
      vars.get(V_QUEUED).setNumber(0);
      return;
    }
    if (lessonActive(scene2)) {
      vars.get(V_QUEUED).setNumber(0);
      return;
    }
    if (doubleTap) vars.get(V_QUEUED).setNumber(2);
    else if (tap) vars.get(V_QUEUED).setNumber(1);
    const charge = vars.get(V_CHARGE_T).getAsNumber();
    if (charge > 0) {
      const next = Math.max(0, charge - dt2);
      vars.get(V_CHARGE_T).setNumber(next);
      if (next <= 0) {
        fireBallAt(
          scene2,
          cannon2,
          aimDeg,
          /*charged*/
          true,
          CHARGED_OPTS
        );
        vars.get(V_FIRE_CD).setNumber(L2_RELOAD_SEC);
      }
      return;
    }
    const queued = vars.get(V_QUEUED).getAsNumber();
    if (cd <= 0 && queued !== 0) {
      vars.get(V_QUEUED).setNumber(0);
      if (queued === 2) {
        vars.get(V_CHARGE_T).setNumber(L2_CHARGE_DELAY_SEC);
      } else {
        fireBallAt(
          scene2,
          cannon2,
          aimDeg,
          /*charged*/
          false,
          {}
        );
        vars.get(V_FIRE_CD).setNumber(L2_RELOAD_SEC);
      }
    }
  }
  function armCatchCan(scene2) {
    scene2.getVariables().get(V_CATCH_ARMED).setNumber(1);
    scene2.getVariables().get(V_CATCH_TEXT_T).setNumber(CATCH_TEXT_SEC);
    console.log(`[level2] Catch-Can! armed double-damage return shot`);
  }
  function boxHit(b, e) {
    const bx = b.getX() + b.getWidth() / 2;
    const by = b.getY() + b.getHeight() / 2;
    return bx >= e.getX() && bx <= e.getX() + e.getWidth() && by >= e.getY() && by <= e.getY() + e.getHeight();
  }
  function ballHit(a, b) {
    return gdjs.RuntimeObject.collisionTest(a, b, false);
  }
  var BULLET_DAMAGE2 = 1;
  var CHARGED_DAMAGE = 2;
  function handleCollisions(scene2, cannon2) {
    const bullets = all(scene2, ObjectName.Bullet).concat(all(scene2, ObjectName.ChargedBullet));
    const enemyBalls = all(scene2, ObjectName.EnemyBall).concat(all(scene2, ObjectName.EnemyRedBall));
    const enemies = allEnemies(scene2);
    for (const b of bullets) {
      const bv = b.getVariables();
      const charged = bv.get("charged").getAsNumber() === 1;
      let consumed = false;
      for (const eb of enemyBalls) {
        if (eb.getVariables().get("catchable").getAsNumber() === 1) continue;
        if (ballHit(b, eb)) {
          const ebx = eb.getX() + eb.getWidth() / 2;
          const eby = eb.getY() + eb.getHeight() / 2;
          const isRed = eb.getVariables().get("red").getAsNumber() === 1;
          eb.deleteFromScene(scene2);
          if (isRed) {
            const firer = findEnemyById(scene2, eb.getVariables().get("firerId").getAsNumber());
            if (firer) damageEnemy(
              scene2,
              firer,
              999,
              /*charged*/
              true
            );
            show(scene2, "DEFLECTED!", ebx, eby, "255;120;90");
            flash2(scene2, "255;240;200", 120);
            playParry();
          } else {
            spawnBurst(scene2, ebx, eby, 40);
            show(scene2, "PARRIED!", ebx, eby, "150;220;255");
            playParry();
          }
          if (charged) {
            bv.get("intercepted").setNumber(1);
          } else {
            b.deleteFromScene(scene2);
            consumed = true;
          }
          break;
        }
      }
      if (consumed) continue;
      if (bv.get("landed").getAsNumber() !== 1) continue;
      for (const e of enemies) {
        if (boxHit(b, e)) {
          const chargedOnly = e.getVariables().get("chargedOnly").getAsNumber() === 1;
          if (chargedOnly && !charged) {
            b.deleteFromScene(scene2);
            break;
          }
          const dmg = charged ? CHARGED_DAMAGE : BULLET_DAMAGE2;
          damageEnemy(scene2, e, dmg, charged);
          b.deleteFromScene(scene2);
          break;
        }
      }
    }
    if (cannon2) {
      const straightMuzzle = cannonMuzzle(cannon2);
      const pivot = cannonCenter2(cannon2);
      const aimDeg = getAimDeg(scene2);
      const aimRad = aimDeg * Math.PI / 180;
      const aimX = Math.cos(aimRad);
      const aimY = Math.sin(aimRad);
      const off = cannon2.getVariables().get("__cannonMuzzleOffset").getAsNumber() || 160;
      const muzzleX = pivot.x + aimX * off;
      const muzzleY = pivot.y + aimY * off;
      const cosTol = Math.cos(CATCH_ANGLE_TOL_DEG * Math.PI / 180);
      for (const eb of enemyBalls) {
        const ev = eb.getVariables();
        const landed = ev.get("landed").getAsNumber() === 1;
        if (ev.get("catchable").getAsNumber() === 1) {
          const bx = eb.getX() + eb.getWidth() / 2;
          const by = eb.getY() + eb.getHeight() / 2;
          const dx = bx - pivot.x;
          const dy = by - pivot.y;
          const len = Math.hypot(dx, dy) || 1;
          const aligned = dx / len * aimX + dy / len * aimY >= cosTol;
          const near = Math.hypot(bx - muzzleX, by - muzzleY) <= CATCH_RADIUS_PX;
          if (aligned && near) {
            eb.deleteFromScene(scene2);
            armCatchCan(scene2);
            spawnBurst(scene2, muzzleX, muzzleY, 90);
            flash2(scene2, "255;245;210", 110);
            show(scene2, "CAUGHT!", muzzleX, muzzleY - 28, "255;230;90");
            playCatch();
            trigger(scene2, 9, 0.22);
          } else if (landed) {
            eb.deleteFromScene(scene2);
            playerHit(scene2, muzzleX, muzzleY, 1);
          }
          continue;
        }
        if (!landed) continue;
        if (ballHit(eb, cannon2) || nearMuzzle(eb, straightMuzzle)) {
          const hx = eb.getX() + eb.getWidth() / 2;
